-- Auto-generated Delta Dental payer rules from 2026 Dentist Handbook
create schema if not exists coding_agent;

create table if not exists coding_agent.payer_rules ( id bigserial primary key, payer_name text not null, payer_plan_scope text not null default 'model_policy', rule_type text not null, code text, transforms_to_code text, related_codes text[], rule_text text not null, conditions jsonb not null default '{}'::jsonb, contract_override_note boolean not null default false, source_id bigint references coding_agent.rule_sources(id) on delete set null, source_page int, evidence_text text, created_at timestamptz not null default now());

create index if not exists payer_rules_code_idx on coding_agent.payer_rules(code);
create index if not exists payer_rules_payer_type_idx on coding_agent.payer_rules(payer_name, rule_type);


;

-- Agent-specific scoped views
create or replace view coding_agent.v_rules_for_coding_agent as select * from coding_agent.payer_rules where rule_type in ('processed_as', 'coverage_rule', 'frequency_limit', 'telehealth_policy');
create or replace view coding_agent.v_rules_for_preauth_agent as select * from coding_agent.payer_rules where rule_type in ('prior_auth', 'documentation_required');
create or replace view coding_agent.v_rules_for_scrubber_agent as select * from coding_agent.payer_rules where rule_type in ('billing_exclusion', 'deny', 'bundling_rule', 'not_billable_to_patient');
create or replace view coding_agent.v_rules_for_estimation_agent as select * from coding_agent.payer_rules where rule_type in ('not_billable_to_patient', 'alternative_benefit', 'processed_as');
create or replace view coding_agent.v_rules_for_appeals_agent as select * from coding_agent.payer_rules;

grant select on coding_agent.payer_rules to service_role, authenticated, anon;
grant select on coding_agent.v_rules_for_coding_agent to service_role, authenticated, anon;
grant select on coding_agent.v_rules_for_preauth_agent to service_role, authenticated, anon;
grant select on coding_agent.v_rules_for_scrubber_agent to service_role, authenticated, anon;
grant select on coding_agent.v_rules_for_estimation_agent to service_role, authenticated, anon;
grant select on coding_agent.v_rules_for_appeals_agent to service_role, authenticated, anon;
